INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(3, 1, '04', '경기 사이클', '문서에서 설명한 4단계 경기 사이클에 포함되지 않는 것은?', 'Expansion', 'Peak', 'Contraction', 'Stagflation', 3, 'docs/04.md는 경기 사이클을 Expansion, Peak, Contraction, Trough 4단계로 설명합니다.'),
(3, 2, '04', '확장기 자산', 'Expansion(확장) 국면에서 유리한 자산 조합으로 맞는 것은?', '주식·원자재·부동산', '채권·금·방어주', '현금·달러·단기채', '금·엔화·유틸리티', 0, '국면별 투자 전략 표에서 확장기는 주식, 원자재, 부동산이 유리한 자산으로 제시됩니다.'),
(3, 3, '04', '정점기 특징', 'Peak(정점) 국면의 경제 특징으로 문서와 일치하는 것은?', 'GDP 급락과 실업 급등', '성장 둔화 시작과 물가 고점', '정부 부양 시작과 저금리', '디플레이션 심화와 소비 급감', 1, '문서 표에서 정점기는 성장 둔화 시작, 물가 고점으로 요약됩니다.'),
(3, 4, '04', '수축기 자산', 'Contraction(수축) 국면에서 상대적으로 유리한 자산은?', '에너지·산업재', '주식·원자재·부동산', '채권·금·방어주', '기술주·경기소비재', 2, '문서는 수축 국면에서 채권, 금, 방어주가 유리하다고 제시합니다.'),
(3, 5, '04', '저점기 전략', 'Trough(저점) 국면에서 문서가 제시한 핵심 관점은?', '인플레 자산 비중 확대', '경기민감주 선매수 기회', '현금 100% 보유', '대출 축소 우선', 1, '저점 국면은 침체 바닥과 정부 부양 시작으로 경기민감주 선매수 기회가 언급됩니다.'),
(3, 6, '04', '섹터 로테이션', '확장 초기 유리한 섹터 조합으로 맞는 것은?', '헬스케어·유틸리티·필수소비재', '소재·에너지·산업재', 'IT·경기소비재·통신', '금융·부동산·필수소비재', 1, '섹터 로테이션 표에서 확장 초기는 소재, 에너지, 산업재가 유리한 섹터입니다.'),
(3, 7, '04', '확장 후기', '확장 후기(EX_L) 유리한 섹터로 제시된 것은?', '에너지·금융', 'IT·경기소비재', '유틸리티·필수소비재', '헬스케어·필수소비재', 0, '문서의 확장 후기 구간은 에너지와 금융 섹터가 유리하다고 설명합니다.'),
(3, 8, '04', '수축기 섹터', '수축 국면에서 유리한 섹터 조합은?', '에너지·소재·금융', '헬스케어·유틸리티·필수소비재', '기술·소비재', '산업재·원자재', 1, '수축 국면 유리 섹터는 헬스케어, 유틸리티, 필수소비재로 정리되어 있습니다.'),
(3, 9, '04', '저점기 섹터', '저점 국면에서 유리한 섹터로 문서에 제시된 것은?', '유틸리티·필수소비재', '에너지·금융', 'IT·경기소비재', '소재·산업재', 2, '문서의 저점(TRO) 구간에는 IT와 경기소비재가 유리한 섹터로 표시됩니다.'),
(3, 10, '04', '선행지표 정의', '선행지표(Leading Indicator)의 설명으로 옳은 것은?', '경기 변화 이후 추세를 확인한다', '현재 경기 상태를 동시에 반영한다', '경기보다 먼저 움직여 미래를 예측하는 데 활용한다', '통화량만 의미한다', 2, '선행지표는 경기보다 먼저 움직이며 미래 경기 예측에 활용된다고 설명합니다.'),
(3, 11, '04', '동행지표 예시', '문서에서 동행지표(Coincident) 예시로 제시된 것은?', 'GDP', '장단기 금리 스프레드', '소비자 기대지수', '실업률', 0, '동행지표 표에는 GDP, 산업생산지수, 취업자 수, 소매판매가 제시됩니다.'),
(3, 12, '04', '후행지표 예시', '후행지표(Lagging) 예시로 맞는 것은?', '건축허가 건수', '주가지수', 'ISM 제조업 PMI', '실업률', 3, '후행지표 표에는 실업률, 대출 잔액, CPI가 포함됩니다.'),
(3, 13, '04', '금리 역전 의미', '장단기 금리 역전의 의미로 문서와 일치하는 것은?', '장기금리 > 단기금리 상태', '단기금리 > 장기금리 상태', '실업률이 0%라는 신호', '물가가 즉시 하락한다는 확정 신호', 1, '문서는 금리 역전을 단기금리가 장기금리보다 높은 상태로 설명합니다.'),
(3, 14, '04', '경기침체 시차', '문서에서 금리 역전 후 실제 경기침체 반영 시차로 제시된 범위는?', '1~3개월', '3~6개월', '6~18개월', '24~36개월', 2, '장단기 금리 역전 경로 도식에서 실제 경기침체는 약 6~18개월 후로 제시됩니다.'),
(3, 15, '04', '스프레드 계산', '문서의 예시에서 장단기 금리 스프레드는 어떻게 계산하는가?', '^IRX - ^TNX', '^TNX - ^IRX', 'CPI - VIX', 'M2 - UNRATE', 1, 'Python 연계 예시에서 스프레드는 10년채(^TNX)에서 3개월채(^IRX)를 뺀 값입니다.'),
(3, 16, '04', '실시간 API 티커', '문서의 실시간 금리 스프레드 조회 예시 tickers 조합은?', '["^GSPC", "^KS11"]', '["^TNX", "^IRX"]', '["M2SL", "CPIAUCSL"]', '["DX-Y.NYB", "KRW=X"]', 1, '시퀀스 다이어그램 예시 요청은 ^TNX와 ^IRX를 사용합니다.'),
(3, 17, '04', '스프레드 해석', '예시에서 스프레드가 -0.85%일 때 문서가 제시한 해석은?', '확장 신호', '정점 신호', '경기침체 경보', '인플레 완화 확정', 2, '문서 노트에 스프레드 음수는 경기침체 경보로 제시되어 있습니다.'),
(3, 18, '04', 'M1 정의', 'M1(협의통화)에 대한 설명으로 옳은 것은?', '중앙은행 본원통화만 의미', 'M1 + 저축예금 + 단기금융상품', '현금 + 요구불예금으로 즉시 사용 가능한 돈', '외환보유액만 집계', 2, '문서 표에서 M1은 현금과 요구불예금으로 구성된 즉시 사용 가능한 통화입니다.'),
(3, 19, '04', 'M2 정의', 'M2(광의통화)에 대한 설명으로 맞는 것은?', 'M0와 동일하다', 'M1 + 저축예금 + 단기 금융상품', '현금만 집계한다', '통화량 지표로 사용하지 않는다', 1, '문서에서 M2는 M1에 저축예금과 단기 금융상품을 더한 일반적 통화량 기준입니다.'),
(3, 20, '04', 'QE 파급', '양적완화(QE) 파급 경로에 대한 설명으로 옳은 것은?', '유동성 감소와 M2 축소', '자산가격 하락 압력 강화', '국채·MBS 매입으로 유동성 증가', '대출비용 즉시 급등', 2, '문서는 QE에서 중앙은행 자산매입이 시중 유동성 증가(M2 급증)로 이어진다고 설명합니다.'),
(3, 21, '04', 'QT 파급', '양적긴축(QT) 효과로 문서와 일치하는 것은?', 'M2 급증과 위험자산 선호', '유동성 감소와 자산가격 하락 압력', '실업률 즉시 0% 달성', '금리 하락 압력 고정', 1, 'QT는 보유채권 미재투자 등으로 유동성 감소, 자산가격 하락 압력을 유발한다고 설명합니다.'),
(3, 22, '04', 'M2와 자산시장', '문서의 M2 증가율-자산시장 관계로 맞는 것은?', 'M2 급증 시 안전자산만 선호', 'M2 감소 시 위험자산 선호 확대', 'M2 급증 시 위험자산 선호와 주식·원자재 상승 압력', 'M2 변화는 자산시장과 무관', 2, 'M2 급증(QE, 재정확장)은 유동성 확대로 위험자산 선호를 높인다고 제시됩니다.'),
(3, 23, '04', 'M2 감소 해석', '문서에서 M2 감소(QT, 금리 인상) 시 나타나는 경향은?', '채권·달러 강세', '주식·원자재 강세', '경기민감주 선매수 확대', 'VIX 급락 고정', 0, 'M2 감소 시 유동성 회수로 안전자산 선호가 강화되어 채권·달러 강세가 제시됩니다.'),
(3, 24, '04', '시장 지표 티커', '시장 데이터 대시보드 코드에서 VIX 티커는?', 'VIXCLS', '^VIX', 'VIX.US', 'VIX=F', 1, '4-4 코드의 MARKET_INDICATORS에서 VIX는 ^VIX로 정의되어 있습니다.'),
(3, 25, '04', 'z-score 해석', '문서의 z-score 기준에서 2 이상은 무엇을 의미하는가?', '보통 범위', '평균보다 약함', '과열 또는 극단적 강세', '극단적 약세', 2, 'z-score 해석 표에서 2 이상은 과열 또는 극단적 강세로 분류됩니다.'),
(3, 26, '04', '국면 점수 규칙', '경기국면 점수화에서 확장 신호로 가산되는 조건은?', 'VIX > 25', 'T10Y2Y < 0', 'M2 YoY < 0', 'VIX < 20', 3, '점수화 예시 코드에서 VIX < 20이면 확장 신호로 점수가 더해집니다.'),
(3, 27, '04', '위험 경보', '위험 경보 규칙에서 danger 레벨을 발생시키는 조건은?', 'M2 YoY > 0', 'VIX > 25', 'T10Y2Y > 0', 'cpi_yoy_diff < 0', 1, 'build_alerts 예시에서 VIX가 25를 초과하면 danger 경보를 추가합니다.'),
(3, 28, '04', '점수 구간', 'macro_score가 5~6일 때 문서의 국면 후보는?', 'Contraction', 'Trough/Recovery', 'Expansion', 'Peak/Overheat', 3, '점수 해석 표에서 5~6은 정점/과열(Peak/Overheat) 구간으로 제시됩니다.'),
(3, 29, '04', '대시보드 API', '문서에서 `/api/macro/dashboard`의 역할로 맞는 것은?', '시뮬레이션 난수만 반환', '위험 경보만 단독 반환', '대시보드 전체 데이터·KPI·경보 반환', '실업률 단일 시계열만 반환', 2, '웹앱/API 고도화 설계 표에서 해당 엔드포인트는 대시보드 전체 데이터와 KPI, 경보를 반환합니다.'),
(3, 30, '04', '리포트 한계', '현황 분석 리포트의 한계 항목으로 문서에 포함된 것은?', '점수화 규칙은 학습용이며 검증 필요', '금리와 물가는 항상 동행', '국면 판정은 단정적 사실', '데이터 발표 시차는 무시 가능', 0, '리포트 템플릿의 한계 항목에 점수화 규칙이 학습용이며 검증이 필요하다고 명시되어 있습니다.');
